44	impl CacheInfo {
45	    /// Return the [`CacheInfo`] for a given timestamp.
46	    pub fn from_timestamp(timestamp: Timestamp) -> Self {
47	        Self {
48	            timestamp: Some(timestamp),
49	            ..Self::default()
50	        }
51	    }
