175	impl std::ops::AddAssign for Removal {
176	    fn add_assign(&mut self, other: Self) {
177	        self.num_files += other.num_files;
178	        self.num_dirs += other.num_dirs;
179	        self.total_bytes += other.total_bytes;
180	    }
181	}
