507	    async fn direct_build<'data>(
508	        &'data self,
509	        source: &'data Path,
510	        subdirectory: Option<&'data Path>,
511	        output_dir: &'data Path,
512	        sources: NoSources,
513	        build_kind: BuildKind,
514	        version_id: Option<&'data str>,
515	    ) -> Result<Option<DistFilename>, BuildDispatchError> {
516	        let source_tree = if let Some(subdir) = subdirectory {
517	            source.join(subdir)
518	        } else {
519	            source.to_path_buf()
520	        };
521	
522	        // Only perform the direct build if the backend is uv in a compatible version.
523	        let source_tree_str = source_tree.display().to_string();
524	        let identifier = version_id.unwrap_or_else(|| &source_tree_str);
525	        if let Err(reason) = check_direct_build(&source_tree, uv_version::version()) {
526	            trace!("Requirements for direct build not matched because {reason}");
527	            return Ok(None);
528	        }
529	
530	        debug!("Performing direct build for {identifier}");
531	
532	        let output_dir = output_dir.to_path_buf();
533	        let filename = tokio::task::spawn_blocking(move || -> Result<_> {
534	            let filename = match build_kind {
535	                BuildKind::Wheel => {
536	                    let wheel = uv_build_backend::build_wheel(
537	                        &source_tree,
538	                        &output_dir,
539	                        None,
540	                        uv_version::version(),
541	                        sources.is_none(),
542	                    )?;
543	                    DistFilename::WheelFilename(wheel)
544	                }
545	                BuildKind::Sdist => {
546	                    let source_dist = uv_build_backend::build_source_dist(
547	                        &source_tree,
548	                        &output_dir,
549	                        uv_version::version(),
550	                        sources.is_none(),
551	                    )?;
552	                    DistFilename::SourceDistFilename(source_dist)
553	                }
554	                BuildKind::Editable => {
555	                    let wheel = uv_build_backend::build_editable(
556	                        &source_tree,
557	                        &output_dir,
558	                        None,
559	                        uv_version::version(),
560	                        sources.is_none(),
561	                    )?;
562	                    DistFilename::WheelFilename(wheel)
563	                }
564	            };
565	            Ok(filename)
566	        })
567	        .await??;
568	
569	        Ok(Some(filename))
570	    }
571	}
