13	/// Prune all unreachable objects from the cache.
14	pub(crate) async fn cache_prune(
15	    ci: bool,
16	    force: bool,
17	    cache: Cache,
18	    printer: Printer,
19	) -> Result<ExitStatus> {
20	    if !cache.root().exists() {
21	        writeln!(
22	            printer.stderr(),
23	            "No cache found at: {}",
24	            cache.root().user_display().cyan()
25	        )?;
26	        return Ok(ExitStatus::Success);
27	    }
28	
29	    let cache = match cache.with_exclusive_lock_no_wait() {
30	        Ok(cache) => cache,
31	        Err(cache) if force => {
32	            debug!("Cache is currently in use, proceeding due to `--force`");
33	            cache
34	        }
35	        Err(cache) => {
36	            writeln!(
37	                printer.stderr(),
38	                "Cache is currently in-use, waiting for other uv processes to finish (use `--force` to override)"
39	            )?;
40	            cache.with_exclusive_lock().await?
41	        }
42	    };
43	
44	    writeln!(
45	        printer.stderr(),
46	        "Pruning cache at: {}",
47	        cache.root().user_display().cyan()
48	    )?;
49	
50	    let mut summary = Removal::default();
51	
52	    // Prune the source distribution cache, which is tightly coupled to the builder crate.
53	    summary += uv_distribution::prune(&cache)
54	        .with_context(|| format!("Failed to prune cache at: {}", cache.root().user_display()))?;
55	
56	    // Prune the remaining cache buckets.
57	    summary += cache
58	        .prune(ci)
59	        .with_context(|| format!("Failed to prune cache at: {}", cache.root().user_display()))?;
60	
61	    // Write a summary of the number of files and directories removed.
62	    match (summary.num_files, summary.num_dirs) {
63	        (0, 0) => {
64	            write!(printer.stderr(), "No unused entries found")?;
65	        }
66	        (0, 1) => {
67	            write!(printer.stderr(), "Removed 1 directory")?;
68	        }
69	        (0, num_dirs_removed) => {
70	            write!(printer.stderr(), "Removed {num_dirs_removed} directories")?;
71	        }
72	        (1, _) => {
73	            write!(printer.stderr(), "Removed 1 file")?;
74	        }
75	        (num_files_removed, _) => {
76	            write!(printer.stderr(), "Removed {num_files_removed} files")?;
77	        }
78	    }
79	
80	    // If any, write a summary of the total byte count removed.
81	    if summary.total_bytes > 0 {
82	        let bytes = if summary.total_bytes < 1024 {
83	            format!("{}B", summary.total_bytes)
84	        } else {
85	            let (bytes, unit) = human_readable_bytes(summary.total_bytes);
86	            format!("{bytes:.1}{unit}")
87	        };
88	        write!(printer.stderr(), " ({})", bytes.green())?;
89	    }
90	
91	    writeln!(printer.stderr())?;
92	
93	    Ok(ExitStatus::Success)
94	}
