```

### Step 2 — Add CLI types (`crates/uv-cli/src/lib.rs`)

In the `CacheCommand` enum, add a new variant after `Size`:

```rust
/// Show a per-bucket breakdown of cache disk usage.
///
/// Displays the disk usage of each cache bucket (wheels, sdists, git, etc.)
/// and a total at the end. By default, outputs sizes in raw bytes; use
/// `--human` for human-readable output.
Stats(StatsArgs),
```

Add `StatsArgs` struct (mirror of `SizeArgs`):

```rust
#[derive(Args, Debug)]
pub struct StatsArgs {
    /// Display the cache sizes in human-readable format (e.g., `1.2 GiB` instead of raw bytes).
    #[arg(long = "human", short = 'H', alias = "human-readable")]
    pub human: bool,
}
```

### Step 3 — Create the implementation (`crates/uv/src/commands/cache_stats.rs`)

```rust
use std::fmt::Write;

use anyhow::Result;
use diskus::DiskUsage;

use crate::commands::{ExitStatus, human_readable_bytes};
use crate::printer::Printer;
use uv_cache::{Cache, CacheBucket};
use uv_preview::{Preview, PreviewFeature};
use uv_warnings::warn_user;

/// Display a per-bucket breakdown of cache disk usage.
pub(crate) fn cache_stats(
    cache: &Cache,
    human_readable: bool,
    printer: Printer,
    preview: Preview,
) -> Result<ExitStatus> {
    if !preview.is_enabled(PreviewFeature::CacheStats) {
        warn_user!(
            "`uv cache stats` is experimental and may change without warning. Pass `--preview-features {}` to disable this warning.",
            PreviewFeature::CacheStats
        );
    }

    if !cache.root().exists() {
        if human_readable {
            writeln!(printer.stdout_important(), "{:<25} {:>10}", "Total", "0B")?;
        } else {
            writeln!(printer.stdout_important(), "{:<25} {:>10}", "Total", "0")?;
        }
        return Ok(ExitStatus::Success);
    }

    let mut total_bytes: u64 = 0;

    for bucket in CacheBucket::iter() {
        let bucket_path = cache.bucket(bucket);
        let bucket_bytes = if bucket_path.exists() {
            let usage = DiskUsage::new(vec![bucket_path]);
            usage.count_ignoring_errors()
        } else {
            0
        };
        total_bytes += bucket_bytes;

        if human_readable {
            let (size, unit) = human_readable_bytes(bucket_bytes);
            writeln!(
                printer.stdout_important(),
                "{:<25} {:>10}",
                bucket.to_string(),
                format!("{size:.1}{unit}"),
            )?;
        } else {
            writeln!(
                printer.stdout_important(),
                "{:<25} {:>10}",
                bucket.to_string(),
                bucket_bytes,
            )?;
        }
    }

    // Print total
    if human_readable {
        let (size, unit) = human_readable_bytes(total_bytes);
        writeln!(
            printer.stdout_important(),
            "{:<25} {:>10}",
            "Total",
            format!("{size:.1}{unit}"),
        )?;
    } else {
        writeln!(
            printer.stdout_important(),
            "{:<25} {:>10}",
            "Total",
            total_bytes,
        )?;
    }

    Ok(ExitStatus::Success)
}
```

**Key notes:**

- `CacheBucket::iter()` is used — it already covers all 10 buckets (Wheels, SourceDistributions, FlatIndex, Git, Interpreter, Simple, Archive, Builds, Environments, Binaries). Note `Python` is intentionally absent from `iter()` — follow the same pattern and do not add it.
- `bucket.to_string()` uses the existing `Display` impl on `CacheBucket` which calls `to_str()`, giving names like `wheels-v6`, `sdists-v9`, etc.
- The "Total" sum is computed independently by summing per-bucket values (not a second full-tree walk), so it's consistent with the per-bucket breakdown.
- `diskus::DiskUsage` is used per-bucket, just like `cache_size` uses it for the root. The `bucket_path.exists()` guard avoids errors on buckets that haven't been created yet.

