12	/// Display the total size of the cache.
13	pub(crate) fn cache_size(
14	    cache: &Cache,
15	    human_readable: bool,
16	    printer: Printer,
17	    preview: Preview,
18	) -> Result<ExitStatus> {
19	    if !preview.is_enabled(PreviewFeature::CacheSize) {
20	        warn_user!(
21	            "`uv cache size` is experimental and may change without warning. Pass `--preview-features {}` to disable this warning.",
22	            PreviewFeature::CacheSize
23	        );
24	    }
25	
26	    if !cache.root().exists() {
27	        if human_readable {
28	            writeln!(printer.stdout_important(), "0B")?;
29	        } else {
30	            writeln!(printer.stdout_important(), "0")?;
31	        }
32	        return Ok(ExitStatus::Success);
33	    }
34	
35	    let disk_usage = DiskUsage::new(vec![cache.root().to_path_buf()]);
36	
37	    let total_bytes = disk_usage.count_ignoring_errors();
38	
39	    if human_readable {
40	        let (bytes, unit) = human_readable_bytes(total_bytes);
41	        writeln!(printer.stdout_important(), "{bytes:.1}{unit}")?;
42	    } else {
43	        writeln!(printer.stdout_important(), "{total_bytes}")?;
44	    }
45	
46	    Ok(ExitStatus::Success)
47	}
