    /// `python3` and `python`.
    ///
    /// If multiple Python versions are requested, uv will exit with an error.
    #[arg(long, conflicts_with("no_bin"))]
    pub default: bool,

    #[command(flatten)]
    pub compile_bytecode: PythonInstallCompileBytecodeArgs,
}

