use std::fmt::Write;

use anyhow::Result;
use diskus::DiskUsage;

use crate::commands::{ExitStatus, human_readable_bytes};
use crate::printer::Printer;
use uv_cache::{Cache, CacheBucket};
use uv_preview::{Preview, PreviewFeature};
use uv_warnings::warn_user;

/// Display a per-bucket breakdown of cache disk usage.
pub(crate) fn cache_stats(
    cache: &Cache,
    human_readable: bool,
    printer: Printer,
    preview: Preview,
) -> Result<ExitStatus> {
    if !preview.is_enabled(PreviewFeature::CacheStats) {
        warn_user!(
            "`uv cache stats` is experimental and may change without warning. Pass `--preview-features {}` to disable this warning.",
            PreviewFeature::CacheStats
        );
    }

    // Compute per-bucket sizes.
    let mut rows: Vec<(String, u64)> = Vec::new();
    let mut total: u64 = 0;

    for bucket in CacheBucket::iter() {
        let path = cache.bucket(bucket);
        let size = if path.exists() {
            let usage = DiskUsage::new(vec![path]);
            usage.count_ignoring_errors()
        } else {
            0
        };
        total = total.saturating_add(size);
        rows.push((format!("{bucket}:"), size));
    }

    // Determine label column width for alignment.
    let label_width = rows
        .iter()
        .map(|(label, _)| label.len())
        .max()
        .unwrap_or(0)
        .max("Total:".len());

    // Print per-bucket rows.
    for (label, size) in &rows {
        if human_readable {
            let (quantity, unit) = human_readable_bytes(*size);
            writeln!(
                printer.stdout_important(),
                "{label:<label_width$}  {quantity:.1}{unit}"
            )?;
        } else {
            writeln!(
                printer.stdout_important(),
                "{label:<label_width$}  {size}"
            )?;
        }
    }

    // Separator.
    writeln!(printer.stdout_important(), "{}", "-".repeat(label_width))?;

    // Total row.
    let total_label = "Total:";
    if human_readable {
        let (quantity, unit) = human_readable_bytes(total);
        writeln!(
            printer.stdout_important(),
            "{total_label:<label_width$}  {quantity:.1}{unit}"
        )?;
    } else {
        writeln!(
            printer.stdout_important(),
            "{total_label:<label_width$}  {total}"
        )?;
    }

    Ok(ExitStatus::Success)
}

