/// Add extra filtering for cache stats output.
///
/// Replaces the size values at the end of each formatted stats line so that
/// snapshot tests remain stable across different cache states.
#[must_use]
pub fn with_filtered_cache_stats(mut self) -> Self {
    // Filter raw byte counts at the end of stats lines (e.g., "wheels-v6:    12345")
    self.filters.push((
        r"(?m)  \d+$".to_string(),
        "  [SIZE]".to_string(),
    ));
    // Filter human-readable sizes at the end of stats lines (e.g., "wheels-v6:    1.2KiB")
    self.filters.push((
        r"(?m)  \d+\.\d+[A-Z][A-Za-z]*$".to_string(),
        "  [SIZE]".to_string(),
    ));
    self
}

